def escape_json_quotes(s: str) -> str:
    """
    将字符串中所有未转义的双引号转为 \"
    保留已转义的 \"
    """
    # 保护已有的 \"
    protected = s.replace('\\"', '\x00').replace('\\n','').replace('\n','')
    # 替换剩余的 "
    escaped = protected.replace('"', '\\"')
    escaped=escaped.replace('\\"{','"{').replace('}\\"','}"')

    # 恢复 \"
    return escaped.replace('\x00', '\\"')

